def modality(**kwargs):

    from ._wavelengths import wavelength_dict as wavel_dict
    from collections import defaultdict

    _band_names = kwargs.get("band_names", None)
    wavelengths = kwargs.get("wavelengths", [])
    if not wavelengths:
        raise ValueError("Wavelengths must be provided to determine modality.")

    if _band_names is not None:
        cleaned_bandnames = [
            band_name.lower().replace("_", "").replace(" ", "")
            for band_name in _band_names
        ]
        if "qa" in cleaned_bandnames:
            qa_idx = cleaned_bandnames.index("qa")
            wavelengths = wavelengths[:qa_idx] + wavelengths[qa_idx + 1 :]

    in_chans = len(wavelengths)

    seen_values = set()
    unique_wavelengths = {}
    for key, value in wavel_dict.items():
        if value not in seen_values:
            unique_wavelengths[key.upper()] = value
            seen_values.add(value)

    unique_wavelengths.update({"CIRRUS": 1.375, "SAR": 55500})
    wavelength_dict = unique_wavelengths

    centers = defaultdict(list)
    for n, w in wavelength_dict.items():
        centers[float(w)].append(n)
    CL = sorted(centers)
    PREF = {"NIR": 0, "NearInfrared": 1, "Blue": 2, "Green": 3, "Red": 4}

    knn = lambda W: [
        min(
            centers[
                min(CL, key=lambda c: abs(w - c) / max(0.05, 0.08 * c, 0.15 * (c >= 8)))
            ],
            key=lambda a: (PREF.get(a, 9), len(a), a),
        )
        for w in W
    ]

    bands = knn(wavelengths)

    invalid_markers = {
        "THERMALINFRARED",
        "THERMALINFRARED_1",
        "THERMALINFRARED_2",
        "PANCHROMATIC",
        "QA",
    }

    if any(b in invalid_markers for b in bands):
        found_invalid = [b for b in bands if b in invalid_markers]
        print(
            f"Warning: Detected non-standard bands for current backbones: {found_invalid}"
        )

    l2a_markers = {
        "VEGETATIONREDEDGE_1",
        "VEGETATIONREDEDGE_2",
        "VEGETATIONREDEDGE_3",
        "SHORTWAVEINFRARED_1",
        "SHORTWAVEINFRARED_2",
        "WATERVAPOR",
    }
    l1c_marker = "CIRRUS"

    if bands[0] == "SAR" or any(b == "SAR" for b in bands):
        mod = "SEN1GRD"
    elif in_chans == 1:
        mod = "DEM"
    elif l1c_marker in bands:
        mod = "SEN2L1C"
    elif any(b in l2a_markers for b in bands):
        mod = "SEN2L2A"
    elif in_chans > 4:
        mod = "SEN2L2A"
    else:
        mod = "SEN2RGB"

    return mod


def checkpoint(func, inputs, params, flag):
    return func(*inputs)


def build_modality_embeddings(
    modality_info, modalities, img_size=None, dim=None, patch_size=None
):
    mod_embeddings = {}
    mod_name_mapping = {}
    for modality in modalities:
        # New modalities can be provided as {"name": <num_channels>}
        if isinstance(modality, dict):
            for key, value in modality.items():
                if isinstance(value, nn.Module):
                    mod_embeddings[key] = value
                elif isinstance(value, int):
                    mod_embeddings[key] = ImageEncoderEmbedding(
                        num_channels=value,
                        dim_tokens=dim,
                        image_size=img_size,
                        patch_size=patch_size,
                        sincos_pos_emb=True,
                    )
                else:
                    raise ValueError(
                        f"Modalities must be provided as a list of strings and dicts. "
                        f"The strings can be any pre-trained modality: "
                        f"RGB, S2L1C, S2L2A, S1RTC, S1GRD, DEM, LULC, NDVI, Coords. "
                        f'Dicts define new modalities with the format {{"<name>": <num_channels>}}. '
                        f"Found {key}: {value} ({type(value)})"
                    )
                mod_name_mapping[key] = key
            continue

        # Cover multiple naming conventions
        modality_renamed = (
            modality.lower()
            .replace("s2", "sen2")
            .replace("s1", "sen1")
            .replace("text", "caption")
            .replace("location", "coords")
        )

        # Get modality key in MODALITY_INFO
        if modality in modality_info.keys():
            key = modality
        elif "sen2l2a" in modality_renamed:
            key = "untok_sen2l2a@224"
        elif "sen2l1c" in modality_renamed:
            key = "untok_sen2l1c@224"
        elif "sen1rtc" in modality_renamed:
            key = "untok_sen1rtc@224"
        elif "sen1grd" in modality_renamed:
            key = "untok_sen1grd@224"
        elif "rgb" in modality_renamed:
            key = "untok_sen2rgb@224"
        elif "dem" in modality_renamed:
            key = "untok_dem@224"
        elif "lulc" in modality_renamed:
            key = "tok_lulc@224"
        elif "ndvi" in modality_renamed:
            key = "tok_ndvi@224"
        elif "caption" in modality_renamed:
            key = "caption"
        elif "coord" in modality_renamed:
            key = "coords"
        else:
            raise NotImplementedError(
                f"Could not find modality {modality} in default modality info."
            )

        mod_info = modality_info[key]
        mod_embeddings[key] = mod_info["encoder_embedding"](
            image_size=img_size, dim_tokens=dim, **mod_info
        )
        mod_name_mapping[modality] = (
            key  # Requires manual mapping for loading model weights
        )

    return mod_embeddings, mod_name_mapping


class LayerNorm(nn.Module):
    """Custom implementation of LayerNorm with the option to disable the bias term"""

    def __init__(self, normalized_shape: int, eps=1e-5, bias=True):
        super().__init__()
        self.eps = eps
        self.weight = nn.Parameter(torch.ones(normalized_shape))
        if bias:
            self.bias = nn.Parameter(torch.zeros(normalized_shape))
        else:
            self.register_buffer("bias", torch.zeros(normalized_shape))

        # Normalized shape must be a tuple for F.layer_norm
        self.normalized_shape = (normalized_shape,)

    def forward(self, x):
        return nn.functional.layer_norm(
            x, self.normalized_shape, self.weight, self.bias, eps=self.eps
        )


def pair(t):
    return t if isinstance(t, tuple) else (t, t)


def build_2d_sincos_posemb(h, w, embed_dim=1024, temperature=10000.0):
    """Sine-cosine positional embeddings as used in MoCo-v3

    Returns positional embedding of shape (1, N, D) where N = W*H
    """
    grid_w = torch.arange(w, dtype=torch.float32)  # Shape (W,)
    grid_h = torch.arange(h, dtype=torch.float32)  # Shape (H, )
    grid_w, grid_h = torch.meshgrid(grid_w, grid_h, indexing="ij")  # Shapes (W, H)
    assert (
        embed_dim % 4 == 0
    ), "Embed dimension must be divisible by 4 for 2D sin-cos position embedding"
    pos_dim = embed_dim // 4
    omega = torch.arange(pos_dim, dtype=torch.float32) / pos_dim  # Shape (D/4,)
    omega = 1.0 / (temperature**omega)
    out_w = torch.einsum(
        "n,d->nd", [grid_w.reshape(-1), omega]
    )  # Outer product, shape (W*H, D/4)
    out_h = torch.einsum(
        "n,d->nd", [grid_h.reshape(-1), omega]
    )  # Outer product, shape (W*H, D/4)
    pos_emb = torch.cat(
        [torch.sin(out_w), torch.cos(out_w), torch.sin(out_h), torch.cos(out_h)], dim=1
    ).unsqueeze(
        0
    )  # Shape (1, W*H, D)
    return pos_emb


def interpolate_pos_encoding(
    pos_embeddings: torch.Tensor, height, width, patch_size, dim_tokens
):
    num_positions = pos_embeddings.shape[1]
    new_height = height // patch_size[0]
    new_width = width // patch_size[1]

    # Assuming squared default image size
    sqrt_num_positions = int(num_positions**0.5)
    pos_embeddings = pos_embeddings.reshape(
        1, sqrt_num_positions, sqrt_num_positions, dim_tokens
    )
    pos_embeddings = pos_embeddings.permute(0, 3, 1, 2)

    pos_embeddings = nn.functional.interpolate(
        pos_embeddings,
        size=(new_height, new_width),
        mode="bicubic",
        align_corners=False,
    )

    pos_embeddings = pos_embeddings.permute(0, 2, 3, 1).view(1, -1, dim_tokens)

    return pos_embeddings


class GatedMlp(nn.Module):
    """Implements SwiGLU and other gated feed-forward layers from Noam Shazeer's paper: https://arxiv.org/abs/2002.05202"""

    def __init__(
        self,
        in_features,
        hidden_features=None,
        out_features=None,
        act_layer=nn.SiLU,
        bias=False,
    ):
        super().__init__()
        out_features = out_features or in_features
        # If gated, multiply hidden_dim by 2/3 to account for extra matmul
        hidden_features = int(2 * (hidden_features or in_features) / 3)
        self.fc1 = nn.Linear(in_features, hidden_features, bias=bias)
        self.act = act_layer()
        self.fc2 = nn.Linear(hidden_features, out_features, bias=bias)
        self.fc3 = nn.Linear(in_features, hidden_features, bias=bias)

    def forward(self, x):
        x = self.fc2(self.act(self.fc1(x)) * self.fc3(x))
        return x


class ImageEncoderEmbedding(nn.Module):
    """Embedding module for spatial inputs, like images or feature maps.
    Creates tokens from patches over the image.

    This adapter / embedding differs from the one of MultiMAE by taking as input a dict and
     separating positional embeddings and modality embeddings from the input projection
     Input projection is 'x', posemb + modemb is 'emb'

    Args:
        num_channels: Number of input channels of the image/feature map
        patch_size: Int or tuple of the patch size over the full image size.
        dim_tokens: Dimension of output tokens. Can be set using init method.
        sincos_pos_emb: Set to True (default) to use fixed 2D sin-cos positional embeddings
        image_size: Default image size. Used to initialize size of positional embeddings.
    """

    def __init__(
        self,
        num_channels: int,
        patch_size: int,
        dim_tokens: int | None = None,
        sincos_pos_emb: bool = True,
        image_size: int = 224,
        **kwargs,
    ):

        super().__init__()
        self.num_channels = num_channels
        self.patch_size = pair(patch_size)
        self.dim_tokens = dim_tokens
        self.sincos_pos_emb = sincos_pos_emb
        self.image_size = pair(image_size)
        self.num_patches = (self.image_size[0] // patch_size) * (
            self.image_size[1] // patch_size
        )

        if self.dim_tokens is not None:
            self.init(dim_tokens=dim_tokens)

    def init(self, dim_tokens: int = 768, init_std=0.02):
        """
        Initialize parts of encoder that are dependent on dimension of tokens.
        Should be called when setting up FourM.

        Args:
            dim_tokens: Dimension of tokens
            init_std: Standard deviation of init
        """
        self.dim_tokens = dim_tokens

        # Task embedding identifying from which task a given token comes from
        # Fixed-size positional embeddings. Can be interpolated to different input sizes
        h_posemb = self.image_size[0] // self.patch_size[0]
        w_posemb = self.image_size[1] // self.patch_size[1]

        pos_emb = build_2d_sincos_posemb(
            h=h_posemb, w=w_posemb, embed_dim=self.dim_tokens
        )
        self.register_buffer("pos_emb", pos_emb)

        self.mod_emb = nn.Parameter(torch.zeros(1, 1, self.dim_tokens))
        nn.init.normal_(self.mod_emb, std=init_std)

        # Image -> tokens projection
        # No bias term here, so modality embedding fully comes from self.mod_emb
        self.proj = nn.Linear(
            self.num_channels * self.patch_size[0] * self.patch_size[1],
            self.dim_tokens,
            bias=False,
        )

    def forward(
        self, d: torch.Tensor | dict[str, torch.Tensor]
    ) -> dict[str, torch.Tensor]:
        """
        Forward pass through embedding module, transforming image to sequence of tokens.
        Creates corresponding modality and positional embeddings and adds them to the dict.

        Args:
            d (torch.Tensor, dict[str, torch.Tensor]): Modality dict with at least the following key:
                - 'tensor' (torch.Tensor): Input image for each batch. Shape (B, C, H, W) where B is the batch size, C is the number of channels, and H, W are height and width of the image.


        Returns:
            dict[str, torch.Tensor]: Modality dict with added keys:
                - 'x' (torch.Tensor): Embedded token sequence. Shape (B, (H / PH) * (W / PW), D), where PH and PW are the patch sizes
                - 'emb' (torch.Tensor): Sum of positional and modality embeddings for the input sequence. Shape (B, (H / PH) * (W / PW), D)
        """
        if not isinstance(d, dict):
            d = {"tensor": d}

        x = d["tensor"]
        B, C, H, W = x.shape
        assert (
            self.dim_tokens is not None
        ), "Need to call init(dim_tokens) function first"
        assert (H % self.patch_size[0] == 0) and (
            W % self.patch_size[1] == 0
        ), f"Image sizes {H}x{W} must be divisible by patch sizes {self.patch_size[0]}x{self.patch_size[1]}"

        # Create patches [B, C, H, W] -> [B, (H*W), C]
        x_patch = self.proj(
            rearrange(
                x,
                "b d (nh ph) (nw pw) -> b (nh nw) (ph pw d)",
                ph=self.patch_size[0],
                pw=self.patch_size[1],
            )
        )

        if (H, W) != self.image_size:

            # Interpolate embedding if required
            pos_emb = interpolate_pos_encoding(
                self.pos_emb.clone(), H, W, self.patch_size, self.dim_tokens
            )
        else:
            pos_emb = self.pos_emb

        # Create positional embedding + modality embedding
        x_emb = repeat(pos_emb + self.mod_emb, "() n d -> b n d", b=B)

        d["x"] = x_patch
        d["emb"] = x_emb

        return d


def generate_uint15_hash(seed_str):
    """Generates a hash of the seed string as an unsigned int15 integer"""
    return int(hashlib.sha256(seed_str.encode("utf-8")).hexdigest(), 16) % (2**15)


class EmbeddingAdapter(nn.Module):
    """
    Wraps a pretrained ImageEncoderEmbedding (or similar) that expects `pretrained_in_channels`.
    The adapter maps `actual_in_channels` -> `pretrained_in_channels` using a 1x1 conv,
    then calls the pretrained embedding with the mapped tensor.
    """

    def __init__(
        self,
        pretrained_embedding: nn.Module,
        actual_in_channels: int,
        pretrained_in_channels: int,
    ):
        super().__init__()
        self.pretrained_embedding = pretrained_embedding
        self.actual_in_channels = actual_in_channels
        self.pretrained_in_channels = pretrained_in_channels

        if actual_in_channels == pretrained_in_channels:
            # no adapter needed
            self.adapter = None
        else:
            self.adapter = nn.Conv2d(
                actual_in_channels, pretrained_in_channels, kernel_size=1, bias=False
            )
            # init as average so mapping is close to identity-ish
            with torch.no_grad():
                self.adapter.weight[:] = (1.0 / actual_in_channels) * torch.ones_like(
                    self.adapter.weight
                )

    def forward(self, d):
        # accept dict or tensor like the original embedding
        if isinstance(d, dict):
            x = d["tensor"]
        else:
            x = d

        if self.adapter is not None:
            x = self.adapter(x)

        # call the wrapped pretrained embedding (which expects dict or tensor)
        if isinstance(d, dict):
            new_d = dict(d)
            new_d["tensor"] = x
            return self.pretrained_embedding(new_d)
        else:
            return self.pretrained_embedding(x)


