def checkpoint_filter_fn(state_dict, model):
    """Manually filter pre-trained weights for TerraMind to enable strict weight loading."""

    model_state_dict = model.state_dict()
    clean_dict = {}
    for k, v in state_dict.items():
        if k in model_state_dict:
            if v.shape == model_state_dict[k].shape:
                clean_dict[k] = v

    missing_params = set(model_state_dict.keys()) - set(clean_dict.keys())
    for k in missing_params:
        clean_dict[k] = model_state_dict[k]

    state_dict = clean_dict

    return state_dict


class TerraMindViT(nn.Module):
    """Modified TerraMind model, adapted to behave as a raw data-only ViT."""

    def __init__(
        self,
        img_size: int = 224,
        merge_method: str | None = "mean",
        patch_size: int = 16,
        in_chans: int = 3,
        dim: int = 768,
        encoder_depth: int = 12,
        num_heads: int = 12,
        mlp_ratio: float = 4.0,
        qkv_bias: bool = True,
        proj_bias: bool = True,
        mlp_bias: bool = True,
        num_register_tokens: int = 0,
        drop_path_rate: float = 0.0,
        drop_rate: float = 0.0,
        attn_drop_rate: float = 0.0,
        modality_drop_rate: float = 0.0,
        act_layer: torch.Tensor = nn.GELU,
        norm_layer: partial | nn.Module = partial(LayerNorm, eps=1e-6, bias=False),
        gated_mlp: bool = False,  # Make the feedforward gated for e.g. SwiGLU
        qk_norm: bool = False,
        encoder_norm: bool = True,
        pretrained: bool = True,
        **kwargs,
    ):
        super().__init__()

        self.is_clf = kwargs.get("is_clf", False)
        modalities = [modality(**kwargs)]
        self.patch_size = patch_size

        if modalities is None or len(modalities) == 0:
            # Init new image modality
            modalities = [{"image": in_chans}]
        elif isinstance(modalities, dict):
            modalities = [modalities]
        elif not isinstance(modalities, list):
            raise ValueError(
                f"Modalities must be None, a list of modality keys or a dict with ints/embedding layers."
            )

        # Build embedding layers for all defined modalities
        mod_embeddings, mod_name_mapping = build_modality_embeddings(
            MODALITY_INFO, modalities, img_size=img_size, dim=dim, patch_size=patch_size
        )
        if self.is_clf:
            key = list(mod_name_mapping.values())[0]
            base_emb = mod_embeddings[key]
            adapted_emb = EmbeddingAdapter(
                base_emb,
                actual_in_channels=in_chans,
                pretrained_in_channels=base_emb.num_channels,
            )
            mod_embeddings[key] = adapted_emb
            self.encoder_embeddings = nn.ModuleDict(mod_embeddings)
        else:
            self.encoder_embeddings = nn.ModuleDict(mod_embeddings)
        self.mod_name_mapping = mod_name_mapping
        self.modalities = list(mod_name_mapping.keys())  # Further code expects list

        self.img_size = img_size
        self.merge_method = merge_method
        self.image_modalities = [
            key
            for key, value in self.encoder_embeddings.items()
            if isinstance(value, ImageEncoderEmbedding)
        ]
        self.modality_drop_rate = modality_drop_rate
        assert 0 <= self.modality_drop_rate <= 1, "modality_drop_rate must be in [0, 1]"

        # stochastic depth decay rule
        dpr = [x.item() for x in torch.linspace(0, drop_path_rate, encoder_depth)]

        self.encoder = nn.ModuleList(
            [
                Block(
                    dim=dim,
                    num_heads=num_heads,
                    mlp_ratio=mlp_ratio,
                    qkv_bias=qkv_bias,
                    proj_bias=proj_bias,
                    drop_path=dpr[i],
                    act_layer=act_layer,
                    norm_layer=norm_layer,
                    gated_mlp=gated_mlp,
                )
                for i in range(encoder_depth)
            ]
        )

        self.out_channels = [dim for i in range(encoder_depth)]

        self.encoder_norm = norm_layer(dim) if encoder_norm else nn.Identity()

        if self.is_clf:
            self.cls_token = nn.Parameter(torch.zeros(1, 1, dim))
            nn.init.normal_(self.cls_token, std=0.02)
            self.head = nn.Linear(dim, kwargs.get("num_classes"))
        else:
            self.head = None

        # Additional register tokens that can be used by the encoder during fine-tuning
        self.num_register_tokens = num_register_tokens
        if self.num_register_tokens > 0:
            self.register_tokens = nn.Parameter(
                torch.zeros(1, self.num_register_tokens, dim)
            )
            nn.init.normal_(self.register_tokens, std=0.02)
        else:
            self.register_tokens = None

        self.tokenizer = nn.ModuleDict({})

        self.output_shape = dict(channels=dim, stride=patch_size)
        if kwargs.get("backbone_name") == "terramind_large":
            temp_ckpt_path = weight_download_url_terramind(
                "fb24291633fa428198cc28498d5fa09f"
            )
            state_dict = torch.load(
                os.path.join(
                    temp_ckpt_path,
                    "TerraMind_v1_large.pt",
                ),
                map_location="cpu",
                weights_only=True,
            )
        else:
            temp_ckpt_path = weight_download_url_terramind(
                "b6d94a2186d74341a3a263f2f1e61579"
            )
            state_dict = torch.load(
                os.path.join(
                    temp_ckpt_path,
                    "TerraMind_v1_base.pt",
                ),
                map_location="cpu",
                weights_only=True,
            )
        state_dict = checkpoint_filter_fn(state_dict, self)
        self.load_state_dict(state_dict, strict=True)

    def freeze_backbone(self):
        """
        Freeze all parameters except norm / layernorm / head parameters
        """

        def _is_norm_name(n):
            nl = n.lower()
            return (
                ("norm" in nl)
                or ("layernorm" in nl)
                or (".ln" in nl)
                or ("ln." in nl)
                or ("head." in nl)
                or (".head" in nl)
            )

        for name, param in self.named_parameters():
            if _is_norm_name(name):
                param.requires_grad = True
            else:
                param.requires_grad = False

    def forward(self, d=None, **kwargs):
        if isinstance(d, torch.Tensor):
            key, tensor = self.modalities[0], d
        else:
            key, tensor = next(iter(d.items()))

        mod = (
            self.mod_name_mapping[key]
            if (key is not None and key in getattr(self, "mod_name_mapping", {}))
            else (self.modalities[0] if getattr(self, "modalities", None) else None)
        )
        if mod in getattr(self, "tokenizer", {}):
            device = next(self.parameters()).device
            enc = self.tokenizer[mod].encode(tensor, device)
            tensor = (
                enc[-1]
                if mod in getattr(self, "image_modalities", [])
                else enc["tensor"]
            )

        if tensor.shape[-2] < self.patch_size or tensor.shape[-1] < self.patch_size:
            h = max(tensor.shape[-2], self.patch_size * 2)
            w = max(tensor.shape[-1], self.patch_size * 2)
            tensor = F.interpolate(tensor, (h, w), mode="bilinear", align_corners=False)

        if (
            tensor.shape[-2] % self.patch_size != 0
            or tensor.shape[-1] % self.patch_size != 0
        ):
            new_h = math.ceil(tensor.shape[-2] / self.patch_size) * self.patch_size
            new_w = math.ceil(tensor.shape[-1] / self.patch_size) * self.patch_size
            tensor = F.interpolate(
                tensor, (new_h, new_w), mode="bilinear", align_corners=False
            )

        m = self.encoder_embeddings[mod](tensor)
        x = m["x"] + m["emb"]

        if getattr(self, "num_register_tokens", 0) > 0:
            x = torch.cat([self.register_tokens.repeat(x.shape[0], 1, 1), x], dim=1)

        if getattr(self, "is_clf", False):
            x = torch.cat([self.cls_token.expand(x.shape[0], -1, -1), x], dim=1)

        out = []
        x_grad_cam = None
        for i, block in enumerate(self.encoder):
            x = block(x)
            if getattr(self, "is_clf", False) and i == (len(self.encoder) - 3):
                x_grad_cam = x
            out.append(x.clone())

        x = self.encoder_norm(x)

        if getattr(self, "is_clf", False):
            return x_grad_cam, x[:, 0]

        out[-1] = x
        return out


def _compute_token_ranges(terra, total_tokens: int) -> dict[str, tuple[int, int]]:
    keys = list(terra.encoder_embeddings.keys())
    reg = int(getattr(terra, "num_register_tokens", 0))
    n = total_tokens - reg
    ranges = {keys[0]: (reg, reg + n)}
    return ranges


def tokens_to_bchw_single(
    tokens: torch.Tensor,
    grid_size: int,
    effective_time_dim: int = 1,
):
    B, N, D = tokens.shape
    gh = gw = grid_size
    t = effective_time_dim
    x = tokens.view(B, t, gh, gw, D)
    x = x.permute(0, 1, 4, 2, 3).contiguous()
    x = x.view(B, t * D, gh, gw)
    return x


class TerraMindAdapter(nn.Module):
    def __init__(
        self,
        terra,
        in_chans,
        layer: int = -1,
        modality: Optional[str] = None,
        remove_cls_token: bool = False,
        effective_time_dim: int = 1,
        h: Optional[int] = None,
        image_size: Optional[tuple[int, int]] = None,
    ):
        super().__init__()
        self._is_vitdet = True
        self.terra = terra
        self.layer = layer
        self.modality = modality
        self.remove_cls_token = remove_cls_token
        self.effective_time_dim = effective_time_dim
        self.h = h
        self.image_size = image_size
        self.output_shape = terra.output_shape

        key = list(terra.mod_name_mapping.values())[0]
        base_emb = terra.encoder_embeddings[key]
        pretrained_expected_ch = getattr(base_emb, "num_channels", 12)
        adapted_emb = EmbeddingAdapter(
            base_emb,
            actual_in_channels=in_chans,
            pretrained_in_channels=pretrained_expected_ch,
        )
        terra.encoder_embeddings[key] = adapted_emb
        self.mod_map = getattr(terra, "mod_name_mapping", {}) or {}

    def _freeze_backone(self):
        self.terra.freeze_backbone()

    def forward(self, x: torch.Tensor):
        if getattr(self.terra, "mod_name_mapping", None):
            ext_key = list(self.terra.mod_name_mapping.keys())[0]
        else:
            ext_key = list(self.terra.encoder_embeddings.keys())[0]

        outs = self.terra({ext_key: x})
        outs_list = outs if isinstance(outs, list) else [outs]
        layer_idx = self.layer if self.layer is not None else -1
        tokens_all = outs_list[layer_idx]  # (B, N_total, D_total)

        total_tokens = tokens_all.shape[1]
        ranges = _compute_token_ranges(self.terra, total_tokens)

        internal_key = self.mod_map.get(ext_key, None)
        s, e = ranges.get(internal_key)
        if e <= s or (e - s) == 0:
            tok = tokens_all
        else:
            tok = tokens_all[:, s:e, :]

        grid_size = int(math.sqrt(tok.shape[1]))
        bchw = tokens_to_bchw_single(
            tok,
            grid_size=grid_size,
            effective_time_dim=self.effective_time_dim,
        )

        return bchw


def weight_download_url_terramind(item_id):
    """
    Returns a function that downloads the weights from the given URL.
    """
    # check Arcgis pro cache dir
    cache_dir = Path.home() / "AppData/Local/ESRI/DeepLearning/terramindv1"

    cache_dir.mkdir(parents=True, exist_ok=True)
    gis = GIS()

    if gis is None:
        raise Exception(
            "Use GIS() to log into your ArcGIS Online or ArcGIS Enterprise account first. A GIS must be provided and/or set as active."
        )
    online_model = gis.content.get(item_id)
    model_path = cache_dir / online_model.name

    if not model_path.exists():
        sys.stderr.write(f"Downloading model to {model_path}\n")

        download_path = online_model.download(save_path=cache_dir)
    else:

        sys.stderr.write(f"Using cached model at {model_path}\n")
        download_path = model_path

    extracted_path = _temp_dlpk(download_path)
    return extracted_path
